#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e4+5;
const int MOD = 1e9+7;
struct Trie{int son[10],fail;}t[N];
int n,len,Cnt,chr[N],nc[N],dp[N][2],f[N][2],Ans;
string s,st[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void BuildTrie(string str){
    int now=0;
    for(char c:str){
        if(!t[now].son[c-'0'])
            t[now].son[c-'0']=(++Cnt);
        now=t[now].son[c-'0'];
        chr[now]=c-'0';
    }nc[now]=1;return;
}
void CountFail(){
    queue<int> q;
    while(!q.empty())q.pop();
    t[0].fail=0;
    for(int i=0;i<10;i++)if(t[0].son[i])
        t[t[0].son[i]].fail=0,q.push(t[0].son[i]);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=0;i<10;i++){
            if(t[u].son[i])
                t[t[u].son[i]].fail=t[t[u].fail].son[i],
                nc[t[u].son[i]]|=nc[t[t[u].son[i]].fail],
                q.push(t[u].son[i]);
            else t[u].son[i]=t[t[u].fail].son[i];
        }
    }return;
}
int main(){
    cin>>s;n=read();
    len=s.size();s=" "+s;
    for(int i=1;i<=n;i++)
        {cin>>st[i];BuildTrie(st[i]);}
    CountFail();
    for(int i=1;i<=s[1]-'0';i++)
        if(!nc[t[0].son[i]])
            dp[t[0].son[i]][(i==s[1]-'0')]++;
    for(int l=2;l<=len;l++){
        for(int i=0;i<=Cnt;i++)
            f[i][0]=dp[i][0],f[i][1]=dp[i][1],
            dp[i][0]=0,dp[i][1]=0;
        for(int x=1;x<=9;x++)
            if(!nc[t[0].son[x]])dp[t[0].son[x]][0]++;
        for(int u=0;u<=Cnt;u++){
            if(nc[u])continue;
            if(f[u][0])
                for(int x=0;x<=9;x++)
                    if(!nc[t[u].son[x]]){
                        int v=t[u].son[x];
                        dp[v][0]=(dp[v][0]+f[u][0])%MOD;
                    }
            if(f[u][1])
                for(int x=0;x<=s[l]-'0';x++)
                    if(!nc[t[u].son[x]]){
                        int v=t[u].son[x];
                        dp[v][(x==s[l]-'0')]=(dp[v][(x==s[l]-'0')]+f[u][1])%MOD;
                    }
        }
    }for(int i=0;i<=Cnt;i++)
        Ans=(Ans+dp[i][0]+dp[i][1])%MOD;
    cout<<Ans<<"\n";
    return 0;
}
